from __future__ import annotations

from dataclasses import dataclass, field


@dataclass
class TemplateElement:
    category: str
    name: str
    brief: str
    detail: str


@dataclass
class TemplateCharacter:
    """模板预设角色。"""

    name: str
    tier: str  # core / supporting / extra
    gender: str = "未知"
    age: int = 0
    occupation: str = ""
    race: str = "人类"
    brief: str = ""
    detail: str = ""
    personality: str = ""
    speech_style: str = ""


@dataclass
class TemplateRelation:
    """模板预设关系（用角色名引用，创建时解析为 ID）。"""

    character_a: str
    character_b: str
    type: str = ""
    direction: str = "bidirectional"
    description: str = ""


@dataclass
class ScaleVariants:
    """某个档位下的预设内容。"""

    characters: list[TemplateCharacter] = field(default_factory=list)
    relations: list[TemplateRelation] = field(default_factory=list)


@dataclass
class WorldTemplate:
    id: str
    title: str
    category: str
    description: str
    plot_summary: str
    core_conflict: str = ""
    tone_and_atmosphere: str = ""
    elements: list[TemplateElement] = field(default_factory=list)
    scales: dict[str, ScaleVariants] = field(default_factory=dict)


TEMPLATES: dict[str, WorldTemplate] = {}


def _register(tpl: WorldTemplate) -> None:
    TEMPLATES[tpl.id] = tpl


def get_template(template_id: str) -> WorldTemplate | None:
    return TEMPLATES.get(template_id)


def list_templates() -> list[WorldTemplate]:
    return list(TEMPLATES.values())


